include/linux/string.h: In function ‘mdd_changelog_ns_store’:
/usr/src/lustre-2.14.56/lustre/include/uapi/linux/lustre/lustre_idl.h:2860:30: note: at offset 64 into source object ‘cr’ of size 64
 2860 |         struct changelog_rec cr; /**< Variable length field */

The solution I can up with is below but I don't really like it. The use of strlen() is causing the headaches since strlen() is being used to read data after the changelog record which gcc sees as a mistake. Ideas?

static inline char *changelog_rec_sname(const struct changelog_rec *rec)
{
        char *cr_name = changelog_rec_name(rec);

        while (*cr_name != '\0') { cr_name++; }

        return cr_name + 1;
}

static inline __kernel_size_t changelog_rec_snamelen(const struct changelog_rec *rec)
{
        unsigned int len = changelog_rec_sname(rec) - changelog_rec_name(rec);

        return rec->cr_namelen - len;
}
